  "LONG-PIPE-DESC:STRING": {
   "name": "LONG-PIPE-DESC:STRING",
   "kind": "global",
   "file": "c2.zil",
   "line": 741,
   "value": "\"You are inside a small ceramic pipe nearly filled with fast-flowing cold\nwater. The walls of the pipe are slippery and overgrown with mossy slime\nwherever an irregularity shields the growth from the force of the water. \""
  },
